SELECT 
    CAST((SELECT COUNT(*) FROM member m1 JOIN major maj1 ON m1.link_to_major = maj1.major_id WHERE maj1.major_name = 'Finance') AS REAL) /
    (SELECT COUNT(*) FROM member m2 JOIN major maj2 ON m2.link_to_major = maj2.major_id WHERE maj2.major_name = 'Physics') AS finance_to_physics_ratio;

